#include <Wire.h>
#include <SPI.h>
extern float kalman_heading_update(float,float,float,float,float*);
volatile long eL=0,eR=0;
void eL0_isr(){eL++;}
void eR0_isr(){eR++;}
void enc_setup(){
  attachInterrupt(0,eL0_isr,CHANGE);
  attachInterrupt(1,eR0_isr,CHANGE);}
float px=0,py=0,hd=0,kP=1.0f;
void imu_setup(){SPI.begin();pinMode(10,OUTPUT);}
float imu_yaw(){return hd;}
void oled_setup(){Wire.begin();}
void oled_draw(float x,float y){(void)x;(void)y;}
void fault_check(){
  if(fabsf(px)>5.0f||fabsf(py)>5.0f){
    Serial.println("FAULT:OOB");while(1);}}
void cmd_parse(){
  if(!Serial.available())return;
  char c=Serial.peek();
  if(c=='R'){Serial.read();px=0;py=0;hd=0;eL=0;eR=0;Serial.println("RESET");}
  else if(c=='P'){Serial.read();
    Serial.print("{");Serial.print("\"x\":");Serial.print(px,3);
    Serial.print(",\"y\":");Serial.print(py,3);Serial.println("}");}}
unsigned long pt=0;
void setup(){Serial.begin(115200);enc_setup();imu_setup();oled_setup();}
void loop(){
  unsigned long n=millis();
  float dt=(n-pt)/1000.0f;
  if(dt<0.02f)return;pt=n;
  long dL=eL;eL=0;
  long dR=eR;eR=0;
  float ds=(dL+dR)*0.00026f;
  float dth=(dR-dL)*0.00026f/0.15f;
  float imu_h=imu_yaw();
  hd=kalman_heading_update(hd,dth,imu_h,dt,&kP);
  px+=ds*cosf(hd);py+=ds*sinf(hd);
  fault_check();cmd_parse();
  oled_draw(px,py);
  if(n%500<20){Serial.print(px,2);Serial.print(',');Serial.println(py,2);}}
